// 1871. Jump Game VII

package problems

import "fmt"

func Problem_1871() {
	s := ""
	minJump := 1
	maxJump := 49999
	fmt.Println(canReach(s, minJump, maxJump))
}

func canReach(s string, minJump int, maxJump int) bool {
	n := len(s)
	// fmt.Println(n)
	if s[n-1] != '0' {
		return false
	}

	dp := make([]bool, n)
	dp[n-1] = true

	i := n - 1 - minJump
	limit := max(0, n-1-maxJump)
	for ; i >= limit; i-- {
		if s[i] == '0' {
			dp[i] = true
		}
	}

	for ; i >= 0; i-- {
		if s[i] == '0' {
			for j := i + minJump; j <= i+maxJump; j++ {
				if dp[j] {
					dp[i] = true
					break
				}
			}
		}
	}

	return dp[0]
}
